import{a as e,i as t,r as n,t as r}from"./app-DJF5ueEI.js";var i=JSON.parse(`{"path":"/blogs/marketplace-rma-system-for-magento-2.html","title":"User Guide of Marketplace RMA System for Magento 2","lang":"en-US","frontmatter":{},"git":{"updatedTime":1783421301000,"contributors":[{"name":"Mohd Munassir Alam","username":"","email":"munassir.alam632@webkul.in","commits":2}],"changelog":[{"hash":"d298d62d27577c7ac248d3bd950813745117e28a","time":1783421301000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"added details for the configuration settings"},{"hash":"fb3987c427827d3b0ba9823e0d47e5fc10fb5399","time":1783420528000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"added RMA Updated Features"}]},"filePathRelative":"blogs/marketplace-rma-system-for-magento-2.md"}`),a={name:`marketplace-rma-system-for-magento-2.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="user-guide-of-marketplace-rma-system-for-magento-2" tabindex="-1"><a class="header-anchor" href="#user-guide-of-marketplace-rma-system-for-magento-2"><span>User Guide of Marketplace RMA System for Magento 2</span></a></h1><p>Updated 7 July 2026</p><p><a href="https://store.webkul.com/magento2-marketplace-rma-system.html" target="_blank" rel="noopener noreferrer">Buy Now</a></p><p><a href="https://webkul.com/blog/magento2-marketplace-rma-system/" target="_blank" rel="noopener noreferrer">Blog Overview</a></p><p>The <strong>Webkul Marketplace RMA System</strong> (<code>Webkul_MpRmaSystem</code>) extends multi-vendor returns for Magento 2. Customers, guests, sellers, and admins can create and manage Return Merchandise Authorization (RMA) requests per seller on marketplace orders.</p><p>This guide covers the <strong>new advanced features</strong> ported from the single-store RMA module, adapted for marketplace multiseller workflows.</p><h2 id="introduction" tabindex="-1"><a class="header-anchor" href="#introduction"><span>Introduction</span></a></h2><h3 id="who-uses-what" tabindex="-1"><a class="header-anchor" href="#who-uses-what"><span>Who Uses What</span></a></h3><table><thead><tr><th>Actor</th><th>Capabilities</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Global configuration, analytics dashboard, RMA grid, fraud badges, wallet refunds</td></tr><tr><td><strong>Seller</strong></td><td>Seller-scoped RMA list, analytics, optional custom workflow/fraud rules</td></tr><tr><td><strong>Customer</strong></td><td>Create RMA from account, order history popup, wallet resolution option</td></tr><tr><td><strong>Guest</strong></td><td>Create RMA with order reference and email verification</td></tr></tbody></table><h3 id="admin-menu-structure" tabindex="-1"><a class="header-anchor" href="#admin-menu-structure"><span>Admin Menu Structure</span></a></h3><p>After enabling the module, open <strong>Marketplace → RMA System</strong>:</p><table><thead><tr><th>Menu Item</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td>Manage RMA Reasons</td><td><code>mprmasystem/reasons</code></td><td>CRUD for return reasons</td></tr><tr><td>RMA Configuration</td><td><code>mprmasystem/configuration/index</code></td><td>General, Workflow, Fraud, and Wallet tabs</td></tr><tr><td>RMA Analytics</td><td><code>mprmasystem/analytics/index</code></td><td>Dashboard charts <strong>and</strong> full RMA management grid</td></tr></tbody></table><p><strong>Note:</strong> The RMA management grid has been moved from <strong>Manage RMA</strong> to the <strong>RMA Analytics</strong> page. The legacy URL <code>mprmasystem/rma/index</code> redirects automatically.</p><h3 id="module-dependencies" tabindex="-1"><a class="header-anchor" href="#module-dependencies"><span>Module Dependencies</span></a></h3><ul><li>Requires <strong>Webkul_Marketplace</strong> (<code>webkul/module-marketplace</code>)</li><li><strong>Wallet refunds</strong> require <strong>Webkul_MpWalletSystem</strong> (or Walletsystem) when using Refund to Wallet</li></ul><h2 id="features-of-marketplace-rma-system" tabindex="-1"><a class="header-anchor" href="#features-of-marketplace-rma-system"><span>Features of Marketplace RMA System</span></a></h2><p>The following advanced features have been added to <strong>Webkul_MpRmaSystem</strong>, ported from the single-store RMA module and adapted for multi-vendor marketplace workflows.</p><h3 id="feature-summary" tabindex="-1"><a class="header-anchor" href="#feature-summary"><span>Feature Summary</span></a></h3><table><thead><tr><th>Feature</th><th>Admin</th><th>Seller</th><th>Customer</th><th>Status</th></tr></thead><tbody><tr><td>Automated Workflow Rules</td><td>✓</td><td>Optional override</td><td>—</td><td>Available</td></tr><tr><td>Fraud Detection &amp; Risk Scoring</td><td>✓</td><td>View badge</td><td>—</td><td>Available</td></tr><tr><td>Analytics Dashboard</td><td>✓ Global</td><td>✓ Scoped</td><td>—</td><td>Available</td></tr><tr><td>RMA Grid on Analytics Page</td><td>✓</td><td>—</td><td>—</td><td>Available</td></tr><tr><td>Wallet Credit Refunds</td><td>✓</td><td>✓</td><td>✓</td><td>Requires MpWalletSystem</td></tr><tr><td>Seller Workflow/Fraud Config</td><td>Enable toggle</td><td>✓</td><td>—</td><td>Available</td></tr><tr><td>Quick Order Cancellation Popup</td><td>—</td><td>—</td><td>✓</td><td>Available</td></tr><tr><td>REST &amp; GraphQL API Parity</td><td>Planned</td><td>Planned</td><td>Planned</td><td>Roadmap</td></tr></tbody></table><h3 id="automated-workflow-rules-engine" tabindex="-1"><a class="header-anchor" href="#automated-workflow-rules-engine"><span>Automated Workflow Rules Engine</span></a></h3><p>Automatically evaluate new RMA requests against configurable rules:</p><ul><li><strong>Auto-approve</strong> when order age, reason, resolution type, customer group, and price range match</li><li><strong>Auto-decline</strong> or route to manual review when rules fail</li><li><strong>Pending RMA alerts</strong> — hourly cron emails admin and seller when RMAs exceed configured hours</li><li><strong>Fraud bypass</strong> — high-risk customers skip auto-approve when manual review is enabled</li><li>Sets <code>rma_pending_notification</code> flag for seller navigation badge</li></ul><p><strong>Admin path:</strong> Marketplace → RMA System → RMA Configuration → <strong>Workflow</strong> tab</p><h3 id="fraud-detection-risk-scoring" tabindex="-1"><a class="header-anchor" href="#fraud-detection-risk-scoring"><span>Fraud Detection &amp; Risk Scoring</span></a></h3><p>Customer return frequency is scored across all sellers (customer-global):</p><ul><li>Rolling window count against configurable limit and period</li><li><code>risk_level</code> and <code>risk_score</code> stored on each RMA record</li><li>Color-coded <strong>Risk Level</strong> column on admin RMA grid</li><li>Read-only risk badge on seller RMA list</li><li>Optional admin email alert on high-risk submission</li></ul><h3 id="analytics-reporting-dashboard" tabindex="-1"><a class="header-anchor" href="#analytics-reporting-dashboard"><span>Analytics &amp; Reporting Dashboard</span></a></h3><p><strong>Admin:</strong> Global statistics with interactive charts, stat cards, and the full <strong>Manage RMA</strong> grid on one page.</p><p><strong>Seller:</strong> Seller-scoped analytics filtered by <code>seller_id</code> — same metrics but only for the logged-in seller&#39;s RMAs.</p><h3 id="wallet-credit-refunds" tabindex="-1"><a class="header-anchor" href="#wallet-credit-refunds"><span>Wallet Credit Refunds</span></a></h3><p>Integrates with <strong>Webkul MpWalletSystem</strong> for marketplace wallet refunds:</p><ul><li>New resolution type: <strong>Refund to Wallet</strong></li><li>Admin <strong>Wallet</strong> configuration tab with enable, customer groups, auto-credit rules</li><li><strong>Refund In Wallet</strong> button for admin and seller</li><li>Auto-credit on workflow approval when configured</li><li>Standard offline refund remains available when configured</li></ul><h3 id="seller-level-configuration" tabindex="-1"><a class="header-anchor" href="#seller-level-configuration"><span>Seller-Level Configuration</span></a></h3><p>When enabled by admin, sellers can customize workflow and fraud rules per account. Settings persist in dedicated seller config tables with a <code>use_custom_config</code> toggle.</p><h3 id="quick-order-cancellation-popup" tabindex="-1"><a class="header-anchor" href="#quick-order-cancellation-popup"><span>Quick Order Cancellation Popup</span></a></h3><p>Customers can initiate returns from <strong>My Account → My Orders</strong> and the <strong>Order View</strong> page. The modal supports item selection, quantities, reasons, resolution types, and <strong>multi-seller</strong> orders.</p><h3 id="notification-count-management" tabindex="-1"><a class="header-anchor" href="#notification-count-management"><span>Notification Count Management</span></a></h3><p>Seller notification badge uses dedicated <code>rma_pending_notification</code> column instead of deriving count from RMA <code>status</code>, matching the Marketplace feedback notification pattern.</p><h3 id="marketplace-specific-rules" tabindex="-1"><a class="header-anchor" href="#marketplace-specific-rules"><span>Marketplace-Specific Rules</span></a></h3><ol><li><strong>One RMA per seller</strong> per request on multi-seller orders</li><li><strong>Fraud scoring</strong> is customer-global across all sellers</li><li><strong>Analytics</strong> admin = global; seller = filtered by <code>seller_id</code></li><li><strong>Wallet credit</strong> uses MpWalletSystem credit memo observer for seller payout handling</li></ol><h2 id="installation-of-marketplace-rma-system" tabindex="-1"><a class="header-anchor" href="#installation-of-marketplace-rma-system"><span>Installation of Marketplace RMA System</span></a></h2><p>Customers receive a <strong>zip folder</strong>. Extract it on your system — the archive contains an <strong>app</strong> folder with the module at <code>app/code/Webkul/MpRmaSystem</code>.</p><p>Transfer the <strong>app</strong> folder into your Magento 2 root directory so the module path is:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">app/code/Webkul/MpRmaSystem/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites"><span>Prerequisites</span></a></h3><ul><li>Magento 2.4.x (Open Source or Adobe Commerce)</li><li><strong>Webkul Marketplace</strong> module installed and enabled</li><li>PHP 8.1+ (per your Magento version requirements)</li></ul><h3 id="install-commands" tabindex="-1"><a class="header-anchor" href="#install-commands"><span>Install Commands</span></a></h3><p>Run from the Magento root directory:</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">php bin/magento setup:upgrade</span>
<span class="line">php bin/magento setup:di:compile</span>
<span class="line">php bin/magento setup:static-content:deploy <span class="token parameter variable">-f</span></span>
<span class="line">php bin/magento indexer:reindex</span>
<span class="line">php bin/magento cache:flush</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="verify-installation" tabindex="-1"><a class="header-anchor" href="#verify-installation"><span>Verify Installation</span></a></h3><ol><li>Log in to <strong>Magento Admin</strong>.</li><li>Confirm <strong>Marketplace → RMA System</strong> appears in the left menu.</li><li>Open <strong>Stores → Configuration</strong> and locate <strong>Marketplace RMA System</strong> section.</li><li>Set <strong>Enable</strong> to <strong>Yes</strong> and save.</li></ol><p>For Adobe Commerce / Enterprise, use the mirrored module at <code>app/code/Webkul/Enterprise/MpRmaSystem/</code>.</p><p>For support policy visit <a href="https://store.webkul.com/support.html/" target="_blank" rel="noopener noreferrer">Webkul Support</a>.</p><h2 id="quick-start-—-marketplace-rma-in-10-minutes" tabindex="-1"><a class="header-anchor" href="#quick-start-—-marketplace-rma-in-10-minutes"><span>Quick Start — Marketplace RMA in 10 Minutes</span></a></h2><h3 id="the-big-picture" tabindex="-1"><a class="header-anchor" href="#the-big-picture"><span>The Big Picture</span></a></h3><table><thead><tr><th>Step</th><th>Task</th></tr></thead><tbody><tr><td>1</td><td>Install &amp; enable module</td></tr><tr><td>2</td><td>Configure general RMA settings</td></tr><tr><td>3</td><td>Set up workflow rules</td></tr><tr><td>4</td><td>Enable fraud detection</td></tr><tr><td>5</td><td>Review analytics &amp; manage RMAs</td></tr></tbody></table><h3 id="step-1-—-install-the-module" tabindex="-1"><a class="header-anchor" href="#step-1-—-install-the-module"><span>Step 1 — Install the Module</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line">php bin/magento setup:upgrade</span>
<span class="line">php bin/magento setup:di:compile</span>
<span class="line">php bin/magento setup:static-content:deploy <span class="token parameter variable">-f</span></span>
<span class="line">php bin/magento indexer:reindex</span>
<span class="line">php bin/magento cache:flush</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Confirm <strong>Marketplace → RMA System</strong> appears in the admin menu.</p><h3 id="step-2-—-enable-rma-general-settings" tabindex="-1"><a class="header-anchor" href="#step-2-—-enable-rma-general-settings"><span>Step 2 — Enable RMA &amp; General Settings</span></a></h3><ol><li>Go to <strong>Stores → Configuration → Marketplace RMA System</strong> (or <strong>Marketplace → RMA System → RMA Configuration</strong>).</li><li>Enable the module and set return window days, allowed product types, and email templates.</li><li>Save configuration.</li></ol><p><img src="/magento-docs/images/mprmasystem/general_settings_configuration.png" alt="General settings"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Module</strong></td><td>Master switch to enable or disable the Marketplace RMA System module.</td></tr><tr><td><strong>Notify Admin on New RMA</strong></td><td>Sends an email notification to the admin when a customer submits a new RMA request.</td></tr><tr><td><strong>Default Allowed Days</strong></td><td>Number of days after order placement during which customers can request a return.</td></tr><tr><td><strong>Admin Email</strong></td><td>Email address used for admin RMA notifications and system alerts.</td></tr><tr><td><strong>Allow Seller Workflow Configuration</strong></td><td>Lets sellers manage automated workflow and pending alert rules from their seller dashboard.</td></tr><tr><td><strong>Allow Seller Fraud Configuration</strong></td><td>Lets sellers manage fraud mitigation and notification settings for their own RMAs.</td></tr><tr><td><strong>New RMA Template</strong></td><td>Transactional email template sent when a new RMA is created.</td></tr><tr><td><strong>RMA Status Update Template</strong></td><td>Email template sent when an RMA status is updated.</td></tr><tr><td><strong>RMA Conversation Template</strong></td><td>Email template used for messages in the RMA conversation thread.</td></tr></tbody></table><h3 id="step-3-—-configure-automated-workflow" tabindex="-1"><a class="header-anchor" href="#step-3-—-configure-automated-workflow"><span>Step 3 — Configure Automated Workflow</span></a></h3><ol><li>Open <strong>Marketplace → RMA System → RMA Configuration</strong>.</li><li>Select the <strong>Workflow</strong> tab.</li><li>Enable the workflow engine, set auto-approve rules, and configure pending alert hours.</li><li>Save.</li></ol><p><img src="/magento-docs/images/mprmasystem/automated_workflow_configuration.png" alt="Workflow configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Automated Workflow Rules</strong></td><td>Master switch to activate or deactivate the entire automated rules engine.</td></tr><tr><td><strong>Enable Auto-Approve Rule</strong></td><td>Automatically approve RMA requests that match all criteria configured below.</td></tr><tr><td><strong>Max Order Age (Days)</strong></td><td>Only auto-approve when the order is no older than this many days. Leave empty to skip this check.</td></tr><tr><td><strong>Allowed Return Reason(s)</strong></td><td>Restrict auto-approve to selected return reasons. Leave empty to allow any reason.</td></tr><tr><td><strong>Allowed Resolution Type(s)</strong></td><td>Restrict auto-approve to selected resolution types (Refund, Replace, Cancel Items, Wallet).</td></tr><tr><td><strong>Allowed Customer Group(s)</strong></td><td>Restrict auto-approve to selected customer groups. Leave empty for all groups.</td></tr><tr><td><strong>Minimum Product Price ($)</strong></td><td>Only auto-approve when returned product price is at or above this value.</td></tr><tr><td><strong>Maximum Product Price ($)</strong></td><td>Only auto-approve when returned product price is at or below this value.</td></tr><tr><td><strong>Auto-Refund Shipping Costs to Wallet</strong></td><td>Include shipping in the wallet refund when auto-approve runs (visible when wallet module is installed).</td></tr><tr><td><strong>Send Approval Email Notification</strong></td><td>Email the customer when their return is automatically approved.</td></tr><tr><td><strong>Enable Pending RMA Alert</strong></td><td>Send alert emails when RMAs remain in pending status too long.</td></tr><tr><td><strong>Hours Threshold</strong></td><td>Number of hours a pending RMA can wait before the alert email is sent (default: 48).</td></tr><tr><td><strong>Manager Email(s)</strong></td><td>Comma-separated recipient list for pending alerts. Uses store contact email if empty.</td></tr><tr><td><strong>Alert Email Template</strong></td><td>Email template used for pending RMA manager alerts.</td></tr><tr><td><strong>Send Test Alert Email</strong></td><td>Sends a sample pending alert using the email and template configured above.</td></tr></tbody></table><h3 id="step-4-—-enable-fraud-detection" tabindex="-1"><a class="header-anchor" href="#step-4-—-enable-fraud-detection"><span>Step 4 — Enable Fraud Detection</span></a></h3><ol><li>On the same configuration page, open the <strong>Fraud</strong> tab.</li><li>Enable fraud detection, set return limit and rolling period.</li><li>Configure manual review bypass and admin notifications.</li><li>Save.</li></ol><p><img src="/magento-docs/images/mprmasystem/rma_fraud_detection_configuration.png" alt="Fraud detection configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Fraud &amp; Risk Scoring</strong></td><td>Tracks customer return frequency and displays risk indicators on admin and seller RMA grids.</td></tr><tr><td><strong>Risk Threshold (Number of Returns)</strong></td><td>Number of returns within the timeframe that flags a customer as High Risk (default: 3).</td></tr><tr><td><strong>Risk Timeframe (Days)</strong></td><td>Rolling window in days used to count customer returns (default: 30).</td></tr><tr><td><strong>Exclude RMA Status(es) from Calculation</strong></td><td>RMAs in selected statuses are ignored when counting returns (e.g. Declined, Canceled).</td></tr><tr><td><strong>Require Manual Review for High-Risk Customers</strong></td><td>High-risk customers always bypass auto-approval and require manual agent review.</td></tr><tr><td><strong>Send Email Alert on High-Risk RMA Request</strong></td><td>Instantly notify administrators when a high-risk customer submits an RMA.</td></tr><tr><td><strong>Notification Email Address(es)</strong></td><td>Comma-separated admin or manager emails that receive fraud alerts.</td></tr><tr><td><strong>Admin Notification Email Template</strong></td><td>Transactional template used for high-risk RMA alert emails.</td></tr><tr><td><strong>Send Test Alert Email</strong></td><td>Sends a sample high-risk alert for testing the configured email and template.</td></tr></tbody></table><h3 id="step-5-—-open-analytics-manage-rmas" tabindex="-1"><a class="header-anchor" href="#step-5-—-open-analytics-manage-rmas"><span>Step 5 — Open Analytics &amp; Manage RMAs</span></a></h3><ol><li>Go to <strong>Marketplace → RMA System → RMA Analytics</strong>.</li><li>Review refund, pending, and declined stat cards.</li><li>Scroll down to the <strong>Manage RMA</strong> grid to view, filter, and edit RMA requests.</li></ol><p><img src="/magento-docs/images/mprmasystem/rma_analytics_adminend.png" alt="Admin analytics and RMA grid"></p><p><strong>Dashboard and grid fields shown in the screenshot:</strong></p><table><thead><tr><th>Section / Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total Refund Given</strong></td><td>Sum of refunded amounts with total RMA count and returned product quantity.</td></tr><tr><td><strong>Total Pending</strong></td><td>Combined value of open RMAs with pending RMA and product counts.</td></tr><tr><td><strong>Declined / Canceled</strong></td><td>Combined value of declined or canceled RMAs with counts.</td></tr><tr><td><strong>Return Rate Over Time</strong></td><td>Chart showing monthly return trends for the last six months.</td></tr><tr><td><strong>Resolution Distribution</strong></td><td>Chart breakdown by resolution type (Refund, Replace, Cancel Items, Wallet).</td></tr><tr><td><strong>RMA Status Distribution</strong></td><td>Chart showing how RMAs are distributed across workflow statuses.</td></tr><tr><td><strong>Top Return Reasons</strong></td><td>Chart of the most frequently selected return reasons.</td></tr><tr><td><strong>Top Returned Products</strong></td><td>Products with the highest return volume.</td></tr><tr><td><strong>Top Return Categories</strong></td><td>Categories with the highest return volume.</td></tr><tr><td><strong>Manage RMA — RMA Id</strong></td><td>Unique RMA record ID; click to open the detail view.</td></tr><tr><td><strong>Manage RMA — Order Ref</strong></td><td>Order increment ID linked to the return request.</td></tr><tr><td><strong>Manage RMA — Customer Name</strong></td><td>Customer who submitted the RMA (links to customer account in admin).</td></tr><tr><td><strong>Manage RMA — Risk Level</strong></td><td>Color-coded fraud risk badge (low, medium, or high).</td></tr><tr><td><strong>Manage RMA — Resolution Type</strong></td><td>Customer-selected resolution for the return.</td></tr><tr><td><strong>Manage RMA — RMA Status</strong></td><td>Current workflow status of the RMA request.</td></tr><tr><td><strong>Manage RMA — Order Status</strong></td><td>Order delivery status associated with the RMA.</td></tr><tr><td><strong>Manage RMA — Seller</strong></td><td>Marketplace seller assigned to the RMA.</td></tr><tr><td><strong>Manage RMA — Action</strong></td><td>Open the RMA detail page to update status, refund, or reply.</td></tr></tbody></table><h3 id="optional-—-wallet-refunds" tabindex="-1"><a class="header-anchor" href="#optional-—-wallet-refunds"><span>Optional — Wallet Refunds</span></a></h3><p>If <strong>Webkul MpWalletSystem</strong> is installed:</p><ol><li>Open the <strong>Wallet</strong> tab under RMA Configuration.</li><li>Enable wallet refunds and configure auto-credit rules.</li><li>Customers can select <strong>Refund to Wallet</strong> when creating an RMA.</li></ol><p><img src="/magento-docs/images/mprmasystem/rma_wallet_configuration.png" alt="Wallet configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Wallet for RMA</strong></td><td>Allows customers to choose <strong>Refund to Wallet</strong> as a resolution type when creating an RMA.</td></tr><tr><td><strong>Allow Standard Refund Alongside Wallet</strong></td><td>Keeps traditional offline or payment refunds available in addition to wallet credit.</td></tr><tr><td><strong>Auto-Credit Wallet on RMA Approval</strong></td><td>Automatically credits the customer wallet when a wallet RMA is approved or marked solved.</td></tr><tr><td><strong>Allowed Customer Group(s)</strong></td><td>Restricts wallet refund to selected customer groups. Leave empty to allow all groups.</td></tr></tbody></table><h3 id="validation-checklist" tabindex="-1"><a class="header-anchor" href="#validation-checklist"><span>Validation Checklist</span></a></h3><ul><li>Customer can create RMA from <strong>My Account → My Returns</strong></li><li>Seller sees RMA in marketplace seller panel with risk badge when applicable</li><li>Auto-approve fires when workflow rules match</li><li>Analytics dashboard loads charts and RMA grid on one page</li><li>High-risk customer RMA shows fraud badge on admin grid</li></ul><h2 id="general-settings-configuration" tabindex="-1"><a class="header-anchor" href="#general-settings-configuration"><span>General Settings Configuration</span></a></h2><p>Configure core RMA behavior from the admin panel before enabling advanced workflow and fraud features.</p><h3 id="access" tabindex="-1"><a class="header-anchor" href="#access"><span>Access</span></a></h3><p><strong>Marketplace → RMA System → RMA Configuration</strong> → <strong>General Settings</strong> tab</p><p>Or: <strong>Stores → Configuration → Marketplace RMA System</strong></p><p><img src="/magento-docs/images/mprmasystem/general_settings_configuration.png" alt="General settings configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Module</strong></td><td>Master switch to enable or disable the Marketplace RMA System module.</td></tr><tr><td><strong>Notify Admin on New RMA</strong></td><td>Sends an email notification to the admin when a customer submits a new RMA request.</td></tr><tr><td><strong>Default Allowed Days</strong></td><td>Number of days after order placement during which customers can request a return.</td></tr><tr><td><strong>Admin Email</strong></td><td>Email address used for admin RMA notifications and system alerts.</td></tr><tr><td><strong>Allow Seller Workflow Configuration</strong></td><td>Lets sellers manage automated workflow and pending alert rules from their seller dashboard.</td></tr><tr><td><strong>Allow Seller Fraud Configuration</strong></td><td>Lets sellers manage fraud mitigation and notification settings for their own RMAs.</td></tr><tr><td><strong>New RMA Template</strong></td><td>Transactional email template sent when a new RMA is created.</td></tr><tr><td><strong>RMA Status Update Template</strong></td><td>Email template sent when an RMA status is updated.</td></tr><tr><td><strong>RMA Conversation Template</strong></td><td>Email template used for messages in the RMA conversation thread.</td></tr></tbody></table><h3 id="configuration-tabs" tabindex="-1"><a class="header-anchor" href="#configuration-tabs"><span>Configuration Tabs</span></a></h3><table><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>General Settings</td><td>Core module enablement and return policies</td></tr><tr><td>Workflow</td><td>Automated approve/decline rules and pending alerts</td></tr><tr><td>Fraud</td><td>Risk scoring and high-return customer detection</td></tr><tr><td>Wallet</td><td>Refund to Wallet rules (visible when wallet module installed)</td></tr></tbody></table><h2 id="automated-workflow-configuration" tabindex="-1"><a class="header-anchor" href="#automated-workflow-configuration"><span>Automated Workflow Configuration</span></a></h2><p>The workflow rules engine evaluates each new RMA against admin-defined criteria and can auto-approve, route to manual review, or trigger pending alerts.</p><h3 id="access-1" tabindex="-1"><a class="header-anchor" href="#access-1"><span>Access</span></a></h3><p><strong>Marketplace → RMA System → RMA Configuration</strong> → <strong>Workflow</strong> tab</p><p><img src="/magento-docs/images/mprmasystem/automated_workflow_configuration.png" alt="Automated workflow configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Automated Workflow Rules</strong></td><td>Master switch to activate or deactivate the entire automated rules engine.</td></tr><tr><td><strong>Enable Auto-Approve Rule</strong></td><td>Automatically approve RMA requests that match all criteria configured below.</td></tr><tr><td><strong>Max Order Age (Days)</strong></td><td>Only auto-approve when the order is no older than this many days. Leave empty to skip this check.</td></tr><tr><td><strong>Allowed Return Reason(s)</strong></td><td>Restrict auto-approve to selected return reasons. Leave empty to allow any reason.</td></tr><tr><td><strong>Allowed Resolution Type(s)</strong></td><td>Restrict auto-approve to selected resolution types (Refund, Replace, Cancel Items, Wallet).</td></tr><tr><td><strong>Allowed Customer Group(s)</strong></td><td>Restrict auto-approve to selected customer groups. Leave empty for all groups.</td></tr><tr><td><strong>Minimum Product Price ($)</strong></td><td>Only auto-approve when returned product price is at or above this value.</td></tr><tr><td><strong>Maximum Product Price ($)</strong></td><td>Only auto-approve when returned product price is at or below this value.</td></tr><tr><td><strong>Auto-Refund Shipping Costs to Wallet</strong></td><td>Include shipping in the wallet refund when auto-approve runs (visible when wallet module is installed).</td></tr><tr><td><strong>Send Approval Email Notification</strong></td><td>Email the customer when their return is automatically approved.</td></tr><tr><td><strong>Enable Pending RMA Alert</strong></td><td>Send alert emails when RMAs remain in pending status too long.</td></tr><tr><td><strong>Hours Threshold</strong></td><td>Number of hours a pending RMA can wait before the alert email is sent (default: 48).</td></tr><tr><td><strong>Manager Email(s)</strong></td><td>Comma-separated recipient list for pending alerts. Uses store contact email if empty.</td></tr><tr><td><strong>Alert Email Template</strong></td><td>Email template used for pending RMA manager alerts.</td></tr><tr><td><strong>Send Test Alert Email</strong></td><td>Sends a sample pending alert using the email and template configured above.</td></tr></tbody></table><h3 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works"><span>How It Works</span></a></h3><ol><li>Customer or guest submits RMA → workflow processor runs after save.</li><li><strong>Fraud detection</strong> runs first — high-risk customers may bypass auto-approve.</li><li>If rules match → status and <code>seller_status</code> update; <code>rma_pending_notification = 1</code> for seller badge.</li><li>Notification emails sent to customer, seller, and admin.</li><li><strong>Cron job</strong> (<code>mprmasystem_pending_rma_alert</code>) runs hourly for overdue pending RMAs.</li></ol><h3 id="email-templates" tabindex="-1"><a class="header-anchor" href="#email-templates"><span>Email Templates</span></a></h3><table><thead><tr><th>Template</th><th>Trigger</th></tr></thead><tbody><tr><td><code>mprmasystem_workflow_auto_action</code></td><td>Auto-approve or auto-decline action</td></tr><tr><td><code>mprmasystem_workflow_alert</code></td><td>Pending RMA exceeds alert threshold</td></tr></tbody></table><p>When <strong>Allow Seller Workflow Config</strong> is enabled, sellers can define custom workflow rules from their dashboard.</p><h2 id="fraud-detection-configuration" tabindex="-1"><a class="header-anchor" href="#fraud-detection-configuration"><span>Fraud Detection Configuration</span></a></h2><p>Fraud detection scores customers by return frequency and flags high-risk RMAs for manual review and admin notification.</p><h3 id="access-2" tabindex="-1"><a class="header-anchor" href="#access-2"><span>Access</span></a></h3><p><strong>Marketplace → RMA System → RMA Configuration</strong> → <strong>Fraud</strong> tab</p><p><img src="/magento-docs/images/mprmasystem/rma_fraud_detection_configuration.png" alt="Fraud detection configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Fraud &amp; Risk Scoring</strong></td><td>Tracks customer return frequency and displays risk indicators on admin and seller RMA grids.</td></tr><tr><td><strong>Risk Threshold (Number of Returns)</strong></td><td>Number of returns within the timeframe that flags a customer as High Risk (default: 3).</td></tr><tr><td><strong>Risk Timeframe (Days)</strong></td><td>Rolling window in days used to count customer returns (default: 30).</td></tr><tr><td><strong>Exclude RMA Status(es) from Calculation</strong></td><td>RMAs in selected statuses are ignored when counting returns (e.g. Declined, Canceled).</td></tr><tr><td><strong>Require Manual Review for High-Risk Customers</strong></td><td>High-risk customers always bypass auto-approval and require manual agent review.</td></tr><tr><td><strong>Send Email Alert on High-Risk RMA Request</strong></td><td>Instantly notify administrators when a high-risk customer submits an RMA.</td></tr><tr><td><strong>Notification Email Address(es)</strong></td><td>Comma-separated admin or manager emails that receive fraud alerts.</td></tr><tr><td><strong>Admin Notification Email Template</strong></td><td>Transactional template used for high-risk RMA alert emails.</td></tr><tr><td><strong>Send Test Alert Email</strong></td><td>Sends a sample high-risk alert for testing the configured email and template.</td></tr></tbody></table><h3 id="risk-scoring-behavior" tabindex="-1"><a class="header-anchor" href="#risk-scoring-behavior"><span>Risk Scoring Behavior</span></a></h3><ul><li>Counts are <strong>customer-global</strong> across all sellers (by <code>customer_id</code>)</li><li>When count ≥ limit within the rolling period → <code>risk_level = high</code>, <code>risk_score</code> populated</li><li>Risk badges appear on admin RMA grid (<strong>RMA Analytics</strong> page) and seller RMA list (read-only)</li></ul><p><img src="/magento-docs/images/mprmasystem/seller/rma_list_with_score.png" alt="Seller RMA list with risk score"></p><p><strong>Grid columns shown in the screenshot:</strong></p><table><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>RMA Id</strong></td><td>Unique return request identifier for the seller&#39;s RMA.</td></tr><tr><td><strong>Order Ref</strong></td><td>Order increment ID linked to the return request.</td></tr><tr><td><strong>Customer Name</strong></td><td>Customer who submitted the RMA.</td></tr><tr><td><strong>Risk Level</strong></td><td>Read-only fraud risk badge showing low, medium, or high risk.</td></tr><tr><td><strong>RMA Status</strong></td><td>Current workflow status of the return for this seller.</td></tr><tr><td><strong>Created At</strong></td><td>Date and time the customer submitted the RMA.</td></tr><tr><td><strong>Action</strong></td><td>Open the RMA detail page to review items, update status, or process refund.</td></tr></tbody></table><p>Fraud detection runs <strong>before</strong> auto-approve. When <strong>Manual Review for High Risk</strong> is enabled, high-risk customers never receive auto-approval even if other workflow rules match.</p><p>Admin alert template: <code>mprmasystem_fraud_detection_admin_alert</code></p><h2 id="wallet-configuration" tabindex="-1"><a class="header-anchor" href="#wallet-configuration"><span>Wallet Configuration</span></a></h2><p>Refund to Wallet allows customers to receive marketplace wallet credit instead of a standard payment refund when <strong>Webkul MpWalletSystem</strong> is installed and configured.</p><h3 id="prerequisites-1" tabindex="-1"><a class="header-anchor" href="#prerequisites-1"><span>Prerequisites</span></a></h3><ul><li><strong>Webkul_MpWalletSystem</strong> (or Walletsystem) installed and enabled</li><li>Wallet module configured with payment methods and seller payout rules</li></ul><p>The Wallet tab appears when the wallet module is detected. If wallet is not installed, the tab shows an installation notice with a link to <a href="https://store.webkul.com/magento2-multi-vendor-wallet.html" target="_blank" rel="noopener noreferrer">MpWalletSystem on Webkul Store</a>.</p><h3 id="access-3" tabindex="-1"><a class="header-anchor" href="#access-3"><span>Access</span></a></h3><p><strong>Marketplace → RMA System → RMA Configuration</strong> → <strong>Wallet</strong> tab</p><p><img src="/magento-docs/images/mprmasystem/rma_wallet_configuration.png" alt="Wallet configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable Wallet for RMA</strong></td><td>Allows customers to choose <strong>Refund to Wallet</strong> as a resolution type when creating an RMA.</td></tr><tr><td><strong>Allow Standard Refund Alongside Wallet</strong></td><td>Keeps traditional offline or payment refunds available in addition to wallet credit.</td></tr><tr><td><strong>Auto-Credit Wallet on RMA Approval</strong></td><td>Automatically credits the customer wallet when a wallet RMA is approved or marked solved.</td></tr><tr><td><strong>Allowed Customer Group(s)</strong></td><td>Restricts wallet refund to selected customer groups. Leave empty to allow all groups.</td></tr></tbody></table><h3 id="refund-flows" tabindex="-1"><a class="header-anchor" href="#refund-flows"><span>Refund Flows</span></a></h3><p><strong>Manual Refund In Wallet:</strong> Admin or seller clicks <strong>Refund In Wallet</strong> on the RMA detail page. A credit memo is created and MpWalletSystem credits the customer wallet.</p><p><strong>Auto Credit:</strong> When <strong>Auto Credit on Approve</strong> is enabled, workflow auto-approve or seller solved status triggers wallet credit automatically.</p><h2 id="analytics-dashboard-rma-management" tabindex="-1"><a class="header-anchor" href="#analytics-dashboard-rma-management"><span>Analytics Dashboard &amp; RMA Management</span></a></h2><p>The admin <strong>RMA Analytics</strong> page combines the analytics dashboard and the full RMA management grid on a single screen.</p><h3 id="access-4" tabindex="-1"><a class="header-anchor" href="#access-4"><span>Access</span></a></h3><p><strong>Marketplace → RMA System → RMA Analytics</strong></p><p>Legacy URL <code>mprmasystem/rma/index</code> redirects here automatically.</p><p><img src="/magento-docs/images/mprmasystem/rma_analytics_adminend.png" alt="Admin analytics dashboard with RMA grid"></p><p><strong>Dashboard and grid fields shown in the screenshot:</strong></p><table><thead><tr><th>Section / Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total Refund Given</strong></td><td>Sum of refunded amounts with total RMA count and returned product quantity.</td></tr><tr><td><strong>Total Pending</strong></td><td>Combined value of open RMAs with pending RMA and product counts.</td></tr><tr><td><strong>Declined / Canceled</strong></td><td>Combined value of declined or canceled RMAs with counts.</td></tr><tr><td><strong>Return Rate Over Time</strong></td><td>Chart showing monthly return trends for the last six months.</td></tr><tr><td><strong>Resolution Distribution</strong></td><td>Chart breakdown by resolution type (Refund, Replace, Cancel Items, Wallet).</td></tr><tr><td><strong>RMA Status Distribution</strong></td><td>Chart showing how RMAs are distributed across workflow statuses.</td></tr><tr><td><strong>Top Return Reasons</strong></td><td>Chart of the most frequently selected return reasons.</td></tr><tr><td><strong>Top Returned Products</strong></td><td>Products with the highest return volume.</td></tr><tr><td><strong>Top Return Categories</strong></td><td>Categories with the highest return volume.</td></tr><tr><td><strong>Manage RMA — RMA Id</strong></td><td>Unique RMA record ID; click to open the detail view.</td></tr><tr><td><strong>Manage RMA — Order Ref</strong></td><td>Order increment ID linked to the return request.</td></tr><tr><td><strong>Manage RMA — Customer Name</strong></td><td>Customer who submitted the RMA (links to customer account in admin).</td></tr><tr><td><strong>Manage RMA — Risk Level</strong></td><td>Color-coded fraud risk badge (low, medium, or high).</td></tr><tr><td><strong>Manage RMA — Resolution Type</strong></td><td>Customer-selected resolution for the return.</td></tr><tr><td><strong>Manage RMA — RMA Status</strong></td><td>Current workflow status of the RMA request.</td></tr><tr><td><strong>Manage RMA — Order Status</strong></td><td>Order delivery status associated with the RMA.</td></tr><tr><td><strong>Manage RMA — Seller</strong></td><td>Marketplace seller assigned to the RMA.</td></tr><tr><td><strong>Manage RMA — Action</strong></td><td>Open the RMA detail page to update status, refund, or reply.</td></tr></tbody></table><h3 id="manage-rma-grid" tabindex="-1"><a class="header-anchor" href="#manage-rma-grid"><span>Manage RMA Grid</span></a></h3><p>Below the dashboard, the <strong>Manage RMA</strong> section displays the full admin RMA grid:</p><ul><li>Filter and sort all marketplace RMAs</li><li>View <strong>Risk Level</strong> fraud badges</li><li>Open RMA detail for status updates, refunds, and conversation</li><li>Mass actions where configured</li></ul><p>Admins can review analytics trends and take action on specific RMAs without switching pages.</p><table><thead><tr><th>Actor</th><th>Data Filter</th></tr></thead><tbody><tr><td>Admin</td><td>All RMAs across all sellers</td></tr><tr><td>Seller</td><td><code>WHERE seller_id = current_seller</code></td></tr></tbody></table><h2 id="seller-configuration" tabindex="-1"><a class="header-anchor" href="#seller-configuration"><span>Seller Configuration</span></a></h2><p>Marketplace sellers can customize <strong>Workflow</strong> and <strong>Fraud Detection</strong> rules when the admin enables seller-level configuration in general settings.</p><h3 id="access-5" tabindex="-1"><a class="header-anchor" href="#access-5"><span>Access</span></a></h3><p><strong>Seller Dashboard → RMA Configuration</strong></p><p>Navigation link appears in the seller account menu when RMA is enabled and seller customization is allowed by admin.</p><h3 id="workflow-tab" tabindex="-1"><a class="header-anchor" href="#workflow-tab"><span>Workflow Tab</span></a></h3><p><img src="/magento-docs/images/mprmasystem/seller/rma_automated_workflow_seller_end.png" alt="Seller workflow configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Use Custom Workflow Rules</strong></td><td>When set to <strong>No</strong>, global admin workflow rules apply to this seller&#39;s RMAs.</td></tr><tr><td><strong>Enable Automated Workflow Rules</strong></td><td>Seller-level master switch for the automated rules engine.</td></tr><tr><td><strong>Enable Auto-Approve Rule</strong></td><td>Auto-approve matching RMAs assigned to this seller.</td></tr><tr><td><strong>Max Order Age (Days)</strong></td><td>Maximum order age eligible for seller auto-approval.</td></tr><tr><td><strong>Allowed Return Reason(s)</strong></td><td>Return reasons eligible for seller auto-approve.</td></tr><tr><td><strong>Allowed Resolution Type(s)</strong></td><td>Resolution types eligible for seller auto-approve.</td></tr><tr><td><strong>Allowed Customer Group(s)</strong></td><td>Customer groups eligible for seller auto-approve.</td></tr><tr><td><strong>Minimum / Maximum Product Price ($)</strong></td><td>Price range filter for seller auto-approve rules.</td></tr><tr><td><strong>Send Approval Email Notification</strong></td><td>Notify customer when seller RMA is auto-approved.</td></tr><tr><td><strong>Enable Pending RMA Alert</strong></td><td>Alert seller or manager when RMAs stay pending too long.</td></tr><tr><td><strong>Hours Threshold</strong></td><td>Hours before pending alert is triggered for this seller.</td></tr><tr><td><strong>Manager Email(s)</strong></td><td>Email recipients for seller pending RMA alerts.</td></tr><tr><td><strong>Alert Email Template</strong></td><td>Template used for seller pending alert notifications.</td></tr></tbody></table><p>Settings persist in <code>marketplace_rma_seller_workflow_config</code>.</p><h3 id="fraud-tab" tabindex="-1"><a class="header-anchor" href="#fraud-tab"><span>Fraud Tab</span></a></h3><p><img src="/magento-docs/images/mprmasystem/seller/rma_fraud_configuration_seller_end.png" alt="Seller fraud configuration"></p><p><strong>Configuration fields shown in the screenshot:</strong></p><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Use Custom Fraud Rules</strong></td><td>When set to <strong>No</strong>, global admin fraud rules apply to this seller&#39;s RMAs.</td></tr><tr><td><strong>Enable Fraud &amp; Risk Scoring</strong></td><td>Enable seller-scoped fraud mitigation settings (risk scoring itself remains customer-global).</td></tr><tr><td><strong>Risk Threshold (Number of Returns)</strong></td><td>Return count that triggers high-risk handling for this seller&#39;s configuration.</td></tr><tr><td><strong>Risk Timeframe (Days)</strong></td><td>Rolling days window for return frequency (inherited scoring logic).</td></tr><tr><td><strong>Exclude RMA Status(es) from Calculation</strong></td><td>Statuses excluded when counting customer returns.</td></tr><tr><td><strong>Require Manual Review for High-Risk Customers</strong></td><td>Block auto-approve for high-risk customers on this seller&#39;s RMAs.</td></tr><tr><td><strong>Send Email Alert on High-Risk RMA Request</strong></td><td>Notify admin when a high-risk RMA is submitted to this seller.</td></tr><tr><td><strong>Notification Email Address(es)</strong></td><td>Admin emails to receive high-risk alerts for this seller.</td></tr><tr><td><strong>Admin Notification Email Template</strong></td><td>Email template for seller-scoped fraud alerts.</td></tr></tbody></table><p>Return frequency scoring remains <strong>customer-global</strong> across all sellers. Seller fraud config controls how high-risk RMAs are handled for that seller&#39;s requests.</p><h3 id="admin-prerequisites" tabindex="-1"><a class="header-anchor" href="#admin-prerequisites"><span>Admin Prerequisites</span></a></h3><p>Admin must enable in <strong>Stores → Configuration → Marketplace RMA System</strong>:</p><ul><li><strong>Allow Seller Workflow Config</strong> = Yes</li><li><strong>Allow Seller Fraud Config</strong> = Yes</li></ul><h2 id="seller-analytics-dashboard" tabindex="-1"><a class="header-anchor" href="#seller-analytics-dashboard"><span>Seller Analytics Dashboard</span></a></h2><p>Sellers view RMA analytics scoped to their own marketplace account — the same metrics as the admin dashboard but filtered by <code>seller_id</code>.</p><h3 id="access-6" tabindex="-1"><a class="header-anchor" href="#access-6"><span>Access</span></a></h3><p><strong>Seller Dashboard → RMA Analytics</strong></p><p><img src="/magento-docs/images/mprmasystem/seller/rma_analytics_seller_end.png" alt="Seller analytics dashboard"></p><p><strong>Dashboard fields shown in the screenshot:</strong></p><table><thead><tr><th>Section / Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Total Refund Given</strong></td><td>Sum and count of refunds processed for this seller&#39;s RMAs only.</td></tr><tr><td><strong>Total Pending</strong></td><td>Open RMA value and count scoped to the logged-in seller.</td></tr><tr><td><strong>Declined / Canceled</strong></td><td>Declined or canceled RMA totals for this seller.</td></tr><tr><td><strong>Return Rate Over Time</strong></td><td>Monthly return rate chart for the seller&#39;s last six months.</td></tr><tr><td><strong>Resolution Distribution</strong></td><td>Breakdown of refund, replace, cancel, and wallet resolutions for this seller.</td></tr><tr><td><strong>RMA Status Distribution</strong></td><td>How this seller&#39;s RMAs are distributed by status.</td></tr><tr><td><strong>Top Return Reasons</strong></td><td>Most common return reasons on this seller&#39;s RMAs.</td></tr><tr><td><strong>Top Returned Products</strong></td><td>Products returned most often from this seller&#39;s catalog.</td></tr><tr><td><strong>Top Return Categories</strong></td><td>Categories with the highest return volume for this seller.</td></tr></tbody></table><p>Seller sees <strong>only</strong> RMAs where <code>marketplace_rma_details.seller_id</code> matches their seller account.</p><h2 id="seller-rma-management" tabindex="-1"><a class="header-anchor" href="#seller-rma-management"><span>Seller RMA Management</span></a></h2><p>Sellers manage return requests assigned to their marketplace account from the seller dashboard RMA list and detail pages.</p><h3 id="rma-list" tabindex="-1"><a class="header-anchor" href="#rma-list"><span>RMA List</span></a></h3><p><strong>Seller Dashboard → Manage RMA</strong> (or RMA List)</p><p><img src="/magento-docs/images/mprmasystem/seller/rma_list_with_score.png" alt="Seller RMA list with risk score"></p><p><strong>Grid columns shown in the screenshot:</strong></p><table><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>RMA Id</strong></td><td>Unique return request identifier for the seller&#39;s RMA.</td></tr><tr><td><strong>Order Ref</strong></td><td>Order increment ID linked to the return request.</td></tr><tr><td><strong>Customer Name</strong></td><td>Customer who submitted the RMA.</td></tr><tr><td><strong>Risk Level</strong></td><td>Read-only fraud risk badge showing low, medium, or high risk.</td></tr><tr><td><strong>RMA Status</strong></td><td>Current workflow status of the return for this seller.</td></tr><tr><td><strong>Created At</strong></td><td>Date and time the customer submitted the RMA.</td></tr><tr><td><strong>Action</strong></td><td>Open the RMA detail page to review items, update status, or process refund.</td></tr></tbody></table><h3 id="rma-detail-view" tabindex="-1"><a class="header-anchor" href="#rma-detail-view"><span>RMA Detail View</span></a></h3><p><img src="/magento-docs/images/mprmasystem/seller/view_rma_seller_end.png" alt="Seller RMA detail view"></p><p><strong>Page sections and fields shown in the screenshot:</strong></p><table><thead><tr><th>Section / Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>RMA # / Date</strong></td><td>RMA identifier and submission date shown in the page header.</td></tr><tr><td><strong>RMA Status badge</strong></td><td>Current status (Pending, Processing, Solved, Declined, or Canceled).</td></tr><tr><td><strong>Risk badge</strong></td><td>Customer fraud risk level and score when fraud detection flagged the request.</td></tr><tr><td><strong>Print</strong></td><td>Download or print the RMA as a PDF document.</td></tr><tr><td><strong>Order</strong></td><td>Linked marketplace order increment ID (opens order view).</td></tr><tr><td><strong>Customer</strong></td><td>Customer name, or Guest for guest RMA requests.</td></tr><tr><td><strong>Resolution</strong></td><td>Customer-selected resolution type (Refund, Replace, Cancel Items, Wallet).</td></tr><tr><td><strong>Delivery Status</strong></td><td>Whether the original order was delivered or not applicable.</td></tr><tr><td><strong>Consignment Number</strong></td><td>Tracking or consignment number provided by the customer after delivery.</td></tr><tr><td><strong>Additional Information</strong></td><td>Free-text notes the customer submitted with the return request.</td></tr><tr><td><strong>Refundable / Refunded Amount</strong></td><td>Amount eligible for refund and amount already refunded (refund/wallet resolutions).</td></tr><tr><td><strong>Customer Images</strong></td><td>Photos uploaded by the customer to support the return.</td></tr><tr><td><strong>Requested Items — Product</strong></td><td>Product name and selected options for each returned line item.</td></tr><tr><td><strong>Requested Items — SKU</strong></td><td>Product SKU for the returned item.</td></tr><tr><td><strong>Requested Items — Price</strong></td><td>Unit price of the returned item.</td></tr><tr><td><strong>Requested Items — Qty</strong></td><td>Quantity the customer requested to return.</td></tr><tr><td><strong>Requested Items — Reason</strong></td><td>Return reason selected for each line item.</td></tr><tr><td><strong>Seller Status</strong></td><td>Dropdown to update seller-side workflow status (pending, received, dispatched, solved, declined).</td></tr><tr><td><strong>Return to Stock</strong></td><td>Restore returned quantity to inventory when applicable (replace resolution).</td></tr><tr><td><strong>Save Status</strong></td><td>Submit the selected seller status update.</td></tr><tr><td><strong>Payment Type</strong></td><td>Choose full or partial refund amount when processing offline refund.</td></tr><tr><td><strong>Refund / Refund In Wallet</strong></td><td>Process standard payment refund or credit customer marketplace wallet.</td></tr><tr><td><strong>Send Message</strong></td><td>Post a reply in the RMA conversation thread with the customer.</td></tr></tbody></table><p>The seller navigation shows a pending notification count from <code>rma_pending_notification = 1</code>, independent of RMA business status.</p><p>Each seller only sees RMAs for their portion of a multi-seller order. Customers create separate RMA requests per seller when returning items from different vendors.</p>`,188)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};